#include <omp.h>
#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <sys/time.h>

#define DEFAULT_ORDER 508

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode;

static inline long long get_time_local() {
	struct timeval tv;
	gettimeofday(&tv, NULL);
	return (tv.tv_sec * 1000000) + tv.tv_usec;
}

void 
findK_parallel(	long height,
				knode *knodes,
				long knodes_elem,
				record *records,
				long *currKnode,
				long *offset,
				int *keys, 
				record *ans,
				int count,
				int order)
{
	int threads_per_block = order < 1024 ? order : 1024;

	#pragma omp parallel num_threads(count * threads_per_block)
	{
		int tid = omp_get_thread_num();
		int bid = tid / threads_per_block;
		int thid = tid % threads_per_block;

		if (bid < count) {
			long local_currKnode = currKnode[bid];
			long local_offset = offset[bid];
			int local_key = keys[bid];

			int i;
			for(i = 0; i < height; i++){

				if(thid < knodes[local_currKnode].num_keys) {
					if((knodes[local_currKnode].keys[thid] <= local_key) && 
					   (thid+1 < knodes[local_currKnode].num_keys + 1 ? knodes[local_currKnode].keys[thid+1] > local_key : 1)){

						if(knodes[local_offset].indices[thid] < knodes_elem){
							local_offset = knodes[local_offset].indices[thid];
						}
					}
				}

				#pragma omp barrier

				if(thid==0){
					currKnode[bid] = local_offset;
					local_currKnode = local_offset;
				}

				#pragma omp barrier
			}

			if(thid < knodes[local_currKnode].num_keys) {
				if(knodes[local_currKnode].keys[thid] == local_key){
					ans[bid].value = records[knodes[local_currKnode].indices[thid]].value;
				}
			}
		}
	}
}

void 
kernel_gpu_cuda_wrapper(record *records,
						long records_mem,
						knode *knodes,
						long knodes_elem,
						long knodes_mem,
						int order,
						long maxheight,
						int count,
						long *currKnode,
						long *offset,
						int *keys,
						record *ans)
{
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time_local();

	time1 = get_time_local();

	time2 = get_time_local();

	time3 = get_time_local();

	findK_parallel(maxheight, knodes, knodes_elem, records, currKnode, offset, keys, ans, count, order);

	time4 = get_time_local();

	time5 = get_time_local();

	time6 = get_time_local();

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", count, order < 1024 ? order : 1024);

	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
	printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n",	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: ALO\n", 					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n",					(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: KERNEL\n",						(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n",				(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: FRE\n", 					(float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time6-time0) / 1000000);
}

void 
kernel_cpu(	int cores_arg,
			record *records,
			knode *knodes,
			long knodes_elem,
			int order,
			long maxheight,
			int count,
			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	kernel_gpu_cuda_wrapper(records, 0, knodes, knodes_elem, 0, order, maxheight, count, currKnode, offset, keys, ans);
}

