void 
findRangeK_parallel(	long height,
						knode *knodes,
						long knodes_elem,
						long *currKnode,
						long *offset,
						long *lastKnode,
						long *offset_2,
						int *start,
						int *end,
						int *Recstart, 
						int *Reclen,
						int count,
						int order)
{
	int threads_per_block = order < 1024 ? order : 1024;

	#pragma omp parallel num_threads(count * threads_per_block)
	{
		int tid = omp_get_thread_num();
		int bid = tid / threads_per_block;
		int thid = tid % threads_per_block;

		if (bid < count) {
			long local_currKnode = currKnode[bid];
			long local_lastKnode = lastKnode[bid];
			long local_offset = offset[bid];
			long local_offset_2 = offset_2[bid];
			int local_start = start[bid];
			int local_end = end[bid];

			int i;
			for(i = 0; i < height; i++){

				if(thid < knodes[local_currKnode].num_keys) {
					if((knodes[local_currKnode].keys[thid] <= local_start) && 
					   (thid+1 < knodes[local_currKnode].num_keys + 1 ? knodes[local_currKnode].keys[thid+1] > local_start : 1)){

						if(knodes[local_currKnode].indices[thid] < knodes_elem){
							local_offset = knodes[local_currKnode].indices[thid];
						}
					}
				}

				if(thid < knodes[local_lastKnode].num_keys) {
					if((knodes[local_lastKnode].keys[thid] <= local_end) && 
					   (thid+1 < knodes[local_lastKnode].num_keys + 1 ? knodes[local_lastKnode].keys[thid+1] > local_end : 1)){

						if(knodes[local_lastKnode].indices[thid] < knodes_elem){
							local_offset_2 = knodes[local_lastKnode].indices[thid];
						}
					}
				}

				#pragma omp barrier

				if(thid==0){
					currKnode[bid] = local_offset;
					lastKnode[bid] = local_offset_2;
					local_currKnode = local_offset;
					local_lastKnode = local_offset_2;
				}

				#pragma omp barrier
			}

			if(thid < knodes[local_currKnode].num_keys) {
				if(knodes[local_currKnode].keys[thid] == local_start){
					Recstart[bid] = knodes[local_currKnode].indices[thid];
				}
			}

			#pragma omp barrier

			if(thid < knodes[local_lastKnode].num_keys) {
				if(knodes[local_lastKnode].keys[thid] == local_end){
					Reclen[bid] = knodes[local_lastKnode].indices[thid] - Recstart[bid] + 1;
				}
			}
		}
	}
}

